vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uvm = vUv;
ret = texture(sampler_main, uvm).x,

ret = mix(
GetBlur1(uvm).x + GetBlur3(uvm).x,
ret,
pow(ret,.5));


vec2 uv3 = (vUv-.5)*(1-GetBlur1(uvm).zzz)+.5;

ret += clamp01(pow(texture(sampler_main, uv3).zzz,.5)*(1-GetBlur1(uvm).x -ret.x)),
ret += clamp01(pow(GetBlur1(uv3).zzz,.5)*(1-GetBlur1(uvm).x -ret.x)),

//ret = pow(ret,vec3(3,.95,.6))*1.25 -.25;
ret -= texture(sampler_main, uvm).yyy,
ret *= ret;

ret = mix(
ret,
ret,
0);


ret = pow(ret,vec3(.5,1,2));
ret *= ret;
ret += texture(sampler_main, uvm).yyy*2,


  fragColor = ret;
}
